import{_ as t,o,c as i,ad as r}from"./chunks/framework.DdcUsuRQ.js";const p=JSON.parse('{"title":"Required roles","description":"Roles flagged required must appear in the resolved palette. Optional roles get synthesised if the seed count is insufficient.","frontmatter":{"title":"Required roles","description":"Roles flagged required must appear in the resolved palette. Optional roles get synthesised if the seed count is insufficient.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/role-schema/required"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/role-schema/required"}],["meta",{"property":"og:title","content":"Required roles: iridis"}],["meta",{"property":"og:description","content":"Roles flagged required must appear in the resolved palette. Optional roles get synthesised if the seed count is insufficient."}],["meta",{"name":"twitter:title","content":"Required roles: iridis"}],["meta",{"name":"twitter:description","content":"Roles flagged required must appear in the resolved palette. Optional roles get synthesised if the seed count is insufficient."}],["meta",{"name":"description","content":"Roles flagged required must appear in the resolved palette. Optional roles get synthesised if the seed count is insufficient."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Role Schema\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":4,\\"name\\":\\"Required roles\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema/required\\"}]}"]]},"headers":[],"relativePath":"reference/role-schema/required.md","filePath":"reference/role-schema/required.md","lastUpdated":1779033869000}'),s={name:"reference/role-schema/required.md"};function a(d,e,n,l,c,h){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="required-roles" tabindex="-1">Required roles <a class="header-anchor" href="#required-roles" aria-label="Permalink to &quot;Required roles&quot;">​</a></h1><p>A role with <code>required: true</code> MUST be present in <code>state.roles</code> after the pipeline runs. If the user supplies fewer seeds than the schema declares roles, the engine synthesises missing <strong>non-required</strong> roles via <code>expand:family</code> derivation; <strong>required</strong> roles never get auto-synthesised; the engine assigns the closest matching seed.</p><h2 id="shape" tabindex="-1">Shape <a class="header-anchor" href="#shape" aria-label="Permalink to &quot;Shape&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>required</code></td><td><code>boolean</code></td><td><code>false</code></td></tr></tbody></table><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p><code>resolve:roles</code> walks the role list and pairs seeds to roles. Required roles get first-pick of seeds; optional roles fill in afterward. If the seed count exceeds the role count, surplus seeds are dropped. If the seed count is less than the role count:</p><ul><li>Required roles still need to be assigned; the engine picks the seed whose OKLCH coordinates are closest to the role&#39;s envelopes.</li><li>Optional roles without a seed are either left absent (consumer sees <code>state.roles[name] === undefined</code>) or synthesised by <code>expand:family</code> if <code>derivedFrom</code> is declared.</li></ul><h2 id="what-it-means" tabindex="-1">What it means <a class="header-anchor" href="#what-it-means" aria-label="Permalink to &quot;What it means&quot;">​</a></h2><p>Required is the <strong>contract</strong> flag. It says &quot;every palette this schema produces MUST have this role&quot;; a downstream consumer that reads <code>state.roles.background</code> can do so unconditionally if <code>background</code> is required. Optional roles encode &quot;nice to have if there&#39;s room.&quot;</p><p>In practice:</p><ul><li><code>background</code>, <code>text</code>, <code>brand</code> are almost always required. The docs site relies on all three resolving.</li><li><code>surface</code>, <code>bg-soft</code>, <code>divider</code> are optional and <code>derivedFrom: background</code> so they always show up regardless of seed count.</li><li><code>success</code>, <code>warning</code>, <code>error</code> are optional with <code>hueLock</code> so they show up only when the schema chose to include them.</li></ul><h2 id="how-to-author" tabindex="-1">How to author <a class="header-anchor" href="#how-to-author" aria-label="Permalink to &quot;How to author&quot;">​</a></h2><ul><li>Mark a role required when downstream consumers would crash without it. The four-tier docs schemas mark <code>background</code>, <code>text</code>, <code>brand</code>, <code>muted</code> required.</li><li>Mark a role optional when it has a sensible parametric definition (<code>derivedFrom</code> + envelope) and the engine can always synthesise it.</li><li>Don&#39;t mark a role required without also providing tight <code>lightnessRange</code> / <code>chromaRange</code> envelopes; the engine will assign a seed regardless and might land in a degenerate slot otherwise.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./derived-from">Derived roles</a>: how optional roles get synthesised when seeds run out.</li><li><a href="./../../concepts/role-schemas">Role schemas overview</a>.</li></ul>',15)])])}const m=t(s,[["render",a]]);export{p as __pageData,m as default};
